const root = $json ?? {};
const body = (root.body && typeof root.body === 'object') ? root.body : {};
const nested = (body.body && typeof body.body === 'object') ? body.body : {};
const input = nested && Object.keys(nested).length ? nested : body;
const payload = input.payload ?? input;
const requestedAction = String(root.action ?? body.action ?? nested.action ?? payload.action ?? root.query?.action ?? 'ping').toLowerCase().trim();
const task = root.task ?? body.task ?? nested.task ?? payload.task ?? root.text ?? body.text ?? nested.text ?? payload.text ?? '';

const headers = root.headers ?? body.headers ?? {};
const host = headers.host ?? headers.Host ?? '';
const protocol = headers['x-forwarded-proto'] ?? headers['X-Forwarded-Proto'] ?? 'https';

let resolvedAction = requestedAction;
let targetPath = 'mcp-ping';
let forwardBody = { action: 'ping', requestedAction };

if (requestedAction === 'planner') {
  targetPath = 'planner-entry';
  forwardBody = { task: task || 'No task provided' };
} else if (requestedAction === 'full_pipeline') {
  targetPath = 'whatsapp-intake';
  forwardBody = { text: task || 'No task provided' };
} else if (requestedAction === 'ping') {
  targetPath = 'mcp-ping';
  forwardBody = { action: 'ping', requestedAction };
} else {
  resolvedAction = 'unsupported';
  targetPath = 'mcp-ping';
  forwardBody = { action: 'ping', requestedAction };
}

const targetUrl = host ? `${protocol}://${host}/webhook/${targetPath}` : `https://invalid-host/webhook/${targetPath}`;

return [{
  json: {
    requestedAction,
    resolvedAction,
    targetPath,
    targetUrl,
    forwardBody
  }
}];

return [{
  json: {
    status: 'ok',
    result: $json,
    timestamp: new Date().toISOString()
  }
}];
